//-------------------------------------------------------------------------
// scwin.name : f_Save
// scwin.desc : 저장
//-------------------------------------------------------------------------

scwin.f_Save = async function() {
    if (ds_port.getModifiedJSON().length == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_001, new Array("항구관리"));
  		return false;
	}

	scwin.pos_rowSts = ds_port.getRowPosition();

	if (await scwin.f_ReqFieldChk()) {	
    	//if ( cfConfirmMsg(MSG_CM_CRM_001)) {	
    	if ( await $c.win.confirm(MSG_CM_CRM_001)) {	
    		//tr_save.Post();
            $c.sbm.execute(sbm_save);
    	}
    }
};

scwin.f_ReqFieldChk = async function() {
	//필수입력항목 체크
    /*
 	if (await $c.gus.cfValidate([gr_port]) == false) {
		return false;
    }
    */

    let validArry = [
        {id:"portCd", name: "항구코드",key:true,mandatory:true}
        ,{id:"portNm", name: "항구명",key:false,mandatory:true}
        ,{id:"cntyCd", name: "국가코드",key:false,mandatory:true}
        ,{id:"useYn", name: "사용여부명",key:false,mandatory:true}
    ];

    let gridName = "항구";
    if(!await $c.gus.cfValidateGrid(gr_port, null, null, validArry, gridName)){
        return false;
    }
	return true;


};

scwin.f_OpenPopUp = function(chgGubun) {

